                eret += quality_bonus*1.0 - macro_bad*0.35
                eret=max(0.45,min(0.985,random.gauss(eret,0.09)))
                if random.random()<eret:
                    cash += e['seats']*e['price']
                else:
                    e['seats']=0
            e['age']+=1
        ents=[e for e in ents if e['seats']>0]
        # costs - assume future manager tapers ops as stale tickets improve but keeps S2 ad tests.
        if rel<=7: ops=248500.0
        elif rel<=28: ops=205000.0
        elif rel<=84: ops=145000.0
        else: ops=95000.0
